// ---- Data de naixement → edat a l'inici de temporada (1 d'octubre) ----
const SEASON_START = new Date(2025, 9, 1); // 1 oct 2025
function parseDate(v) {
  if (v == null || v === "") return null;
  if (v instanceof Date) return isNaN(v.getTime()) ? null : v;
  if (typeof v === "number") { const d = new Date(Math.round((v - 25569) * 86400000)); return isNaN(d.getTime()) ? null : d; }
  const d = new Date(v); return isNaN(d.getTime()) ? null : d;
}
function ageAtSeason(birth) {
  const b = parseDate(birth); if (!b) return null;
  let a = SEASON_START.getFullYear() - b.getFullYear();
  const m = SEASON_START.getMonth() - b.getMonth();
  if (m < 0 || (m === 0 && SEASON_START.getDate() < b.getDate())) a--;
  return a;
}
function studentAge(s) { const a = ageAtSeason(s && s.naixement); return a != null ? a : (+(s && s.edat) || 0); }
function birthMonth(s) { const b = parseDate(s && s.naixement); return b ? b.getMonth() + 1 : null; }
const MONTHS_CA = ["", "gener", "febrer", "març", "abril", "maig", "juny", "juliol", "agost", "setembre", "octubre", "novembre", "desembre"];
function isBorderline(s) { const m = birthMonth(s); return m === 11 || m === 12; } // compleix anys just després del tall d'octubre

// Color identificatiu de cada nivell (per als diplomes)
const LEVEL_THEME = {
  "Nadons Pares": { c: "#E08A2B" },                 // taronja
  "Nadons Alt": { c: "#D8443B" },                   // roig
  "Infants Baix": { c: "#2E7CC4" },                 // blau
  "Infants Mig-Alt": { c: "#7A57C2" },              // lila
  "Xiquets Iniciació-Mitjà": { c: "#2FA36B" },      // verd
  "Xiquets Mitjà-Perfeccionament": { c: "#0E8C8C" },// turquesa
};
const themeOf = (lvl) => LEVEL_THEME[lvl] || { c: "var(--gold)" };

/* ============================ SEED ============================ */
function mulberry32(a) { return function () { a |= 0; a = (a + 0x6D2B79F5) | 0; let t = Math.imul(a ^ (a >>> 15), 1 | a); t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t; return ((t ^ (t >>> 14)) >>> 0) / 4294967296; }; }
const FIRST = ["Aitana", "Marc", "Lucia", "Pau", "Nora", "Hugo", "Ona", "Bruno", "Jana", "Leo", "Carla", "Izan", "Vera", "Biel", "Lia", "Nil", "Emma", "Joel", "Abril", "Gael", "Martina", "Pol", "Noa", "Roc", "Sofia", "Èric", "Alba", "Teo", "Daniela", "Aleix"];
const LAST = ["Soler", "Marí", "Ferré", "Box", "Pla", "Sanz", "Gil", "Roig", "Mas", "Vidal", "Tur", "Bou", "Lluch", "Penya", "Server", "Aledo"];
function seedStudents() {
  const rng = mulberry32(42); const out = []; let code = 5000;
  const baseAge = { "Nadons Pares": 1, "Nadons Alt": 2, "Infants Baix": 3, "Infants Mig-Alt": 4, "Xiquets Iniciació-Mitjà": 6, "Xiquets Mitjà-Perfeccionament": 9 };
  GROUPS.forEach((g) => {
    const n = 5 + Math.floor(rng() * 4);
    for (let i = 0; i < n; i++) {
      const nom = `${FIRST[Math.floor(rng() * FIRST.length)]} ${LAST[Math.floor(rng() * LAST.length)]} ${LAST[Math.floor(rng() * LAST.length)]}`;
      const id = code++;
      const email = rng() < 0.85 ? `familia.${id}@exemple.com` : "";
      const octAge = (baseAge[g.nivell] || 6) + Math.floor(rng() * 2);
      const month = rng() < 0.16 ? (rng() < 0.5 ? 11 : 12) : 1 + Math.floor(rng() * 9);
      const day = 1 + Math.floor(rng() * 27);
      const naixement = `${2025 - octAge}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
      out.push({ id, nom, email, naixement, grupId: g.id });
    }
  });
  return out;
}
function seedEvaluations(students) {
  const rng = mulberry32(7); const ev = {};
  students.forEach((st, idx) => {
    if (idx % 7 === 0) return; // alguns pendents
    const g = groupById(st.grupId); const items = itemsOf(g.nivell); const sc = {};
    const bias = rng(); // perfil de l'alumne
    items.forEach((it) => {
      const r = rng();
      let v;
      if (bias > 0.7) v = r < 0.15 ? 3 : 4;
      else if (bias > 0.35) v = r < 0.2 ? 2 : r < 0.6 ? 3 : 4;
      else v = r < 0.35 ? 2 : r < 0.7 ? 3 : 4;
      sc[it.id] = v;
    });
    ev[`25-26:${st.id}`] = { scores: sc, monitor: g.monitor };
  });
  return ev;
}
